record.field:
services:
  typebot-db:
    image: postgres:14-alpine
    restart: always
    volumes:
    - ./db_data:/var/lib/postgresql/data
    environment:
      POSTGRES_USER: typebot
      POSTGRES_DB: typebot
      POSTGRES_PASSWORD: typebot
    container_name: '{{ INSTANCE_CODE }}_typebot_db'
    networks:
    - internal
  typebot-builder:
    image: baptistearno/typebot-builder:2.27
    restart: always
    depends_on:
    - typebot-db
    environment:
      ENCRYPTION_SECRET: {{ encryption_secret }}
      DATABASE_URL: postgresql://typebot:typebot@typebot-db:5432/typebot
      NEXTAUTH_URL: {{ nextauth_url }}
      NEXT_PUBLIC_VIEWER_URL: {{ next_public_viewer_url }}
      ADMIN_EMAIL: {{ admin_email }}
      SMTP_HOST: {{ smtp_host }}
      NEXT_PUBLIC_SMTP_FROM: {{ next_public_smtp_from }}
      SMTP_USERNAME: {{ smtp_username }}
      SMTP_PASSWORD: {{ smtp_password }}
      DEFAULT_WORKSPACE_PLAN: {{ default_workspace_plan }}
    container_name: '{{ INSTANCE_CODE }}'
    ports:
    - '{{ PORT_HTTP }}:3000'
    networks:
    - internal
    - agz-proxy-network
  typebot-viewer:
    image: baptistearno/typebot-viewer:2.27.0
    restart: always
    environment:
      ENCRYPTION_SECRET: {{ encryption_secret }}
      DATABASE_URL: postgresql://typebot:typebot@typebot-db:5432/typebot
      NEXTAUTH_URL: {{ nextauth_url }}
      NEXT_PUBLIC_VIEWER_URL: {{ next_public_viewer_url }}
      ADMIN_EMAIL: {{ admin_email }}
      SMTP_HOST: {{ smtp_host }}
      NEXT_PUBLIC_SMTP_FROM: {{ next_public_smtp_from }}
      SMTP_USERNAME: {{ smtp_username }}
      SMTP_PASSWORD: {{ smtp_password }}
      DEFAULT_WORKSPACE_PLAN: {{ default_workspace_plan }}
    container_name: '{{ INSTANCE_CODE }}_typebot_viewer'
    networks:
    - internal
networks:
  internal:
    driver: bridge
  agz-proxy-network:
    external: true
